33	
34	library IEEE;
35	use			IEEE.STD_LOGIC_1164.all;
36	use			IEEE.NUMERIC_STD.all;
37	
38	library PoC;
39	use			PoC.utils.all;
40	
41	
42	entity bus_Arbiter is
43		generic (
44			STRATEGY									: string										:= "RR";			-- RR, LOT
45			PORTS											: positive									:= 1;
46			WEIGHTS										: T_INTVEC									:= (0 => 1);
47			OUTPUT_REG								: boolean										:= TRUE
48		);
49		port (
50			Clock											: in	std_logic;
51			Reset											: in	std_logic;
52	
53			Arbitrate									: in	std_logic;
54			Request_Vector						: in	std_logic_vector(PORTS - 1 downto 0);
55	
56			Arbitrated								: out	std_logic;
57			Grant_Vector							: out	std_logic_vector(PORTS - 1 downto 0);
58			Grant_Index								: out	std_logic_vector(log2ceilnz(PORTS) - 1 downto 0)
59		);
60	end entity;
61	
62	
63	architecture rtl of bus_Arbiter is
64		attribute KEEP										: boolean;
65		attribute FSM_ENCODING						: string;
66	
67	begin
68	
69		-- Assert STRATEGY for known strings
70		-- ==========================================================================================================================================================
71		assert ((STRATEGY = "RR") or (STRATEGY = "LOT"))
72			report "Unknown arbiter strategy." severity FAILURE;
73	
74		-- Round Robin Arbiter
75		-- ==========================================================================================================================================================
76		genRR : if STRATEGY = "RR" generate
77			signal RequestLeft								: unsigned(PORTS - 1 downto 0);
78			signal SelectLeft									: unsigned(PORTS - 1 downto 0);
79			signal SelectRight								: unsigned(PORTS - 1 downto 0);
80	
81			signal ChannelPointer_en					: std_logic;
82			signal ChannelPointer							: std_logic_vector(PORTS - 1 downto 0);
83			signal ChannelPointer_d						: std_logic_vector(PORTS - 1 downto 0)								:= to_slv(1, PORTS);
84			signal ChannelPointer_nxt					: std_logic_vector(PORTS - 1 downto 0);
85	
86		begin
87	
88			ChannelPointer_en		<= Arbitrate;
89	
90			RequestLeft					<= (not ((unsigned(ChannelPointer_d) - 1) or unsigned(ChannelPointer_d))) and unsigned(Request_Vector);
91			SelectLeft					<= (unsigned(not RequestLeft) + 1)		and RequestLeft;
92			SelectRight					<= (unsigned(not Request_Vector) + 1)	and unsigned(Request_Vector);
93			ChannelPointer_nxt	<= std_logic_vector(ite((RequestLeft = (RequestLeft'range => '0')), SelectRight, SelectLeft));
94	
95			-- generate ChannelPointer register and unregistered outputs
96			genREG0 : if not OUTPUT_REG generate
97				process(Clock)
98				begin
99					if rising_edge(Clock) then
100						if (Reset = '1') then
101							ChannelPointer_d		<= to_slv(1, PORTS);
102						elsif (ChannelPointer_en = '1') then
103							ChannelPointer_d		<= ChannelPointer_nxt;
104						end if;
105					end if;
106				end process;
107	
108				Arbitrated				<= Arbitrate;
109				Grant_Vector			<= ChannelPointer_nxt;
110				Grant_Index				<= std_logic_vector(onehot2bin(ChannelPointer_nxt));
111			end generate;
112	
113			-- generate ChannelPointer register and registered outputs
114			genREG1 : if OUTPUT_REG generate
115				signal ChannelPointer_bin_d				: std_logic_vector(log2ceilnz(PORTS) - 1 downto 0)		:= (others => '0');
116			begin
117				process(Clock)
118				begin
119					if rising_edge(Clock) then
120						if (Reset = '1') then
121							ChannelPointer_d			<= to_slv(1, PORTS);
122							ChannelPointer_bin_d	<=  (others => '0');
123						elsif (ChannelPointer_en = '1') then
124							ChannelPointer_d			<= ChannelPointer_nxt;
125							ChannelPointer_bin_d	<= std_logic_vector(onehot2bin(ChannelPointer_nxt));
126						end if;
127					end if;
128				end process;
129	
130				Arbitrated				<= Arbitrate when rising_edge(Clock);
131				Grant_Vector			<= ChannelPointer_d;
132				Grant_Index				<= ChannelPointer_bin_d;
133			end generate;
134		end generate;
135	
136		-- Lottery Arbiter
137		-- ==========================================================================================================================================================
138	--	genLOT : if (STRATEGY = "RR") generate
139	--	begin
140	--
141	--	end generate;
142	end architecture;
