32	library IEEE;
33	use			IEEE.STD_LOGIC_1164.all;
34	use			IEEE.NUMERIC_STD.all;
35	
36	library PoC;
37	use			PoC.utils.all;
38	use			PoC.vectors.all;
39	use			PoC.strings.all;
40	
41	
42	package stream is
43		-- single dataword for TestRAM
44		type T_SIM_STREAM_WORD_8 is record
45			Valid			: std_logic;
46			Data			: T_SLV_8;
47			SOF				: std_logic;
48			EOF				: std_logic;
49			Ready			: std_logic;
50			EOFG			: boolean;
51		end record;
52	
53		type T_SIM_STREAM_WORD_32 is record
54			Valid			: std_logic;
55			Data			: T_SLV_32;
56			SOF				: std_logic;
57			EOF				: std_logic;
58			Ready			: std_logic;
59			EOFG			: boolean;
60		end record;
61	
62		-- define array indices
63		constant C_SIM_STREAM_MAX_PATTERN_COUNT			: positive			:= 128;-- * 1024;				-- max data size per testcase
64		constant C_SIM_STREAM_MAX_FRAMEGROUP_COUNT	: positive			:= 8;
65	
66		constant C_SIM_STREAM_WORD_INDEX_BW					: positive			:= log2ceilnz(C_SIM_STREAM_MAX_PATTERN_COUNT);
67		constant C_SIM_STREAM_FRAMEGROUP_INDEX_BW		: positive			:= log2ceilnz(C_SIM_STREAM_MAX_FRAMEGROUP_COUNT);
68	
69		subtype T_SIM_STREAM_WORD_INDEX					is integer range 0 to C_SIM_STREAM_MAX_PATTERN_COUNT - 1;
70		subtype T_SIM_STREAM_FRAMEGROUP_INDEX		is integer range 0 to C_SIM_STREAM_MAX_FRAMEGROUP_COUNT - 1;
71	
72		subtype T_SIM_DELAY											is T_UINT_16;
73		type		T_SIM_DELAY_VECTOR							is array (natural range <>) of T_SIM_DELAY;
74	
75		-- define array of datawords
76		type		T_SIM_STREAM_WORD_VECTOR_8			is array (natural range <>) of T_SIM_STREAM_WORD_8;
77		type		T_SIM_STREAM_WORD_VECTOR_32			is array (natural range <>) of T_SIM_STREAM_WORD_32;
78	
79		-- define link layer directions
80		type		T_SIM_STREAM_DIRECTION					is (Send, RECEIVE);
81	
82		-- define framegroup information
83		type T_SIM_STREAM_FRAMEGROUP_8 is record
84			Active					: boolean;
85			Name						: string(1 to 64);
86			PrePause				: natural;
87			PostPause				: natural;
88			DataCount				: T_SIM_STREAM_WORD_INDEX;
89			Data						: T_SIM_STREAM_WORD_VECTOR_8(0 to C_SIM_STREAM_MAX_PATTERN_COUNT - 1);
90		end record;
91	
92		type T_SIM_STREAM_FRAMEGROUP_32 is record
93			Active					: boolean;
94			Name						: string(1 to 64);
95			PrePause				: natural;
96			PostPause				: natural;
97			DataCount				: T_SIM_STREAM_WORD_INDEX;
98			Data						: T_SIM_STREAM_WORD_VECTOR_32(T_SIM_STREAM_WORD_INDEX);
99		end record;
100	
101		-- define array of framegroups
102		type T_SIM_STREAM_FRAMEGROUP_VECTOR_8			is array (natural range <>) of T_SIM_STREAM_FRAMEGROUP_8;
103		type T_SIM_STREAM_FRAMEGROUP_VECTOR_32		is array (natural range <>) of T_SIM_STREAM_FRAMEGROUP_32;
104	
105		-- define constants (stored in RAMB36's parity-bits)
106		constant C_SIM_STREAM_WORD_8_EMPTY			: T_SIM_STREAM_WORD_8		:= (Valid => '0', Data => (others => 'U'),	SOF => '0', EOF	=> '0', Ready => '0', EOFG => FALSE);
107		constant C_SIM_STREAM_WORD_32_EMPTY			: T_SIM_STREAM_WORD_32	:= (Valid => '0', Data => (others => 'U'),	SOF => '0', EOF	=> '0', Ready => '0', EOFG => FALSE);
108		constant C_SIM_STREAM_WORD_8_INVALID		: T_SIM_STREAM_WORD_8		:= (Valid	=> '0', Data => (others => 'U'),	SOF => '0', EOF	=> '0', Ready => '0', EOFG => FALSE);
109		constant C_SIM_STREAM_WORD_32_INVALID		: T_SIM_STREAM_WORD_32	:= (Valid	=> '0', Data => (others => 'U'),	SOF => '0', EOF	=> '0', Ready => '0', EOFG => FALSE);
110		constant C_SIM_STREAM_WORD_8_ZERO				: T_SIM_STREAM_WORD_8		:= (Valid	=> '1', Data => (others => 'Z'),	SOF => '0', EOF	=> '0', Ready => '0', EOFG => FALSE);
111		constant C_SIM_STREAM_WORD_32_ZERO			: T_SIM_STREAM_WORD_32	:= (Valid	=> '1', Data => (others => 'Z'),	SOF => '0', EOF	=> '0', Ready => '0', EOFG => FALSE);
112		constant C_SIM_STREAM_WORD_8_UNDEF			: T_SIM_STREAM_WORD_8		:= (Valid	=> '1', Data => (others => 'U'),	SOF => '0', EOF	=> '0', Ready => '0', EOFG => FALSE);
113		constant C_SIM_STREAM_WORD_32_UNDEF			: T_SIM_STREAM_WORD_32	:= (Valid	=> '1', Data => (others => 'U'),	SOF => '0', EOF	=> '0', Ready => '0', EOFG => FALSE);
114	
115		constant C_SIM_STREAM_FRAMEGROUP_8_EMPTY	: T_SIM_STREAM_FRAMEGROUP_8		:= (
116			Active						=> FALSE,
117			Name							=> (others => C_POC_NUL),
118			PrePause					=> 0,
119			PostPause					=> 0,
120			DataCount					=> 0,
121			Data							=> (others => C_SIM_STREAM_WORD_8_EMPTY)
122		);
123		constant C_SIM_STREAM_FRAMEGROUP_32_EMPTY	: T_SIM_STREAM_FRAMEGROUP_32	:= (
124			Active						=> FALSE,
125			Name							=> (others => C_POC_NUL),
126			PrePause					=> 0,
127			PostPause					=> 0,
128			DataCount					=> 0,
129			Data							=> (others => C_SIM_STREAM_WORD_32_EMPTY)
130		);
131	
132		function CountPatterns(Data : T_SIM_STREAM_WORD_VECTOR_8)		return natural;
133		function CountPatterns(Data : T_SIM_STREAM_WORD_VECTOR_32)	return natural;
134	
135		function dat(slv		: T_SLV_8)										return T_SIM_STREAM_WORD_8;
136		function dat(slvv		: T_SLVV_8) 									return T_SIM_STREAM_WORD_VECTOR_8;
137		function dat(slv		: T_SLV_32)										return T_SIM_STREAM_WORD_32;
138		function dat(slvv		: T_SLVV_32)									return T_SIM_STREAM_WORD_VECTOR_32;
139		function sof(slv		: T_SLV_8)										return T_SIM_STREAM_WORD_8;
140		function sof(slvv		: T_SLVV_8) 									return T_SIM_STREAM_WORD_VECTOR_8;
141		function sof(slv		: T_SLV_32)										return T_SIM_STREAM_WORD_32;
142		function sof(slvv		: T_SLVV_32)									return T_SIM_STREAM_WORD_VECTOR_32;
143		function eof(slv		: T_SLV_8)										return T_SIM_STREAM_WORD_8;
144		function eof(slvv		: T_SLVV_8) 									return T_SIM_STREAM_WORD_VECTOR_8;
145		function eof(slv		: T_SLV_32)										return T_SIM_STREAM_WORD_32;
146		function eof(slvv		: T_SLVV_32)									return T_SIM_STREAM_WORD_VECTOR_32;
147		function eof(stmw		: T_SIM_STREAM_WORD_8)				return T_SIM_STREAM_WORD_8;
148		function eof(stmwv	: T_SIM_STREAM_WORD_VECTOR_8)	return T_SIM_STREAM_WORD_VECTOR_8;
149		function eof(stmw		: T_SIM_STREAM_WORD_32)				return T_SIM_STREAM_WORD_32;
150		function eofg(stmw	: T_SIM_STREAM_WORD_8)				return T_SIM_STREAM_WORD_8;
151		function eofg(stmwv	: T_SIM_STREAM_WORD_VECTOR_8)	return T_SIM_STREAM_WORD_VECTOR_8;
152		function eofg(stmw	: T_SIM_STREAM_WORD_32)				return T_SIM_STREAM_WORD_32;
153	
154		function to_string(stmw : T_SIM_STREAM_WORD_8)		return string;
155		function to_string(stmw : T_SIM_STREAM_WORD_32)		return string;
156	
157		-- checksum functions
158		-- ================================================================
159		function sim_CRC8(words		: T_SIM_STREAM_WORD_VECTOR_8) return std_logic_vector;
160	--	function sim_CRC16(words	: T_SIM_STREAM_WORD_VECTOR_8) return STD_LOGIC_VECTOR;
161	end;
162	
163	
164	package body stream is
165	function CountPatterns(Data : T_SIM_STREAM_WORD_VECTOR_8) return natural is
166		begin
167			for i in 0 to Data'length - 1 loop
168				if (Data(i).EOFG = TRUE) then
169					return i + 1;
170				end if;
171			end loop;
172	
173			return 0;
174		end;
175	
176		function CountPatterns(Data : T_SIM_STREAM_WORD_VECTOR_32) return natural is
177		begin
178			for i in 0 to Data'length - 1 loop
179				if (Data(i).EOFG = TRUE) then
180					return i + 1;
181				end if;
182			end loop;
183	
184			return 0;
185		end;
186	
187		function dat(slv : T_SLV_8) return T_SIM_STREAM_WORD_8 is
188			variable result : T_SIM_STREAM_WORD_8;
189		begin
190			result := (Valid => '1', Data	=> slv,	SOF	=> '0',	EOF	=> '0', Ready => '-', EOFG => FALSE);
191			report "dat: " & to_string(result) severity NOTE;
192			return result;
193		end;
194	
195		function dat(slvv : T_SLVV_8) return T_SIM_STREAM_WORD_VECTOR_8 is
196			variable result			: T_SIM_STREAM_WORD_VECTOR_8(slvv'range);
197		begin
198			for i in slvv'range loop
199				result(i)		:= dat(slvv(i));
200			end loop;
201	
202			return result;
203		end;
204	
205		function dat(slv : T_SLV_32) return T_SIM_STREAM_WORD_32 is
206			variable result : T_SIM_STREAM_WORD_32;
207		begin
208			result := (Valid => '1', Data	=> slv,	SOF	=> '0',	EOF	=> '0', Ready => '-', EOFG => FALSE);
209			report "dat: " & to_string(result) severity NOTE;
210			return result;
211		end;
212	
213		function dat(slvv : T_SLVV_32) return T_SIM_STREAM_WORD_VECTOR_32 is
214			variable result			: T_SIM_STREAM_WORD_VECTOR_32(slvv'range);
215		begin
216			for i in slvv'range loop
217				result(i)		:= dat(slvv(i));
218			end loop;
219	
220			return result;
221		end;
222	
223		function sof(slv : T_SLV_8) return T_SIM_STREAM_WORD_8 is
224			variable result : T_SIM_STREAM_WORD_8;
225		begin
226			result := (Valid => '1', Data	=> slv,	SOF	=> '1',	EOF	=> '0', Ready => '-', EOFG => FALSE);
227			report "sof: " & to_string(result) severity NOTE;
228			return result;
229		end;
230	
231		function sof(slvv : T_SLVV_8) return T_SIM_STREAM_WORD_VECTOR_8 is
232			variable result			: T_SIM_STREAM_WORD_VECTOR_8(slvv'range);
233		begin
234			result(slvv'low)		:= sof(slvv(slvv'low));
235			for i in slvv'low + 1 to slvv'high loop
236				result(i)		:= dat(slvv(i));
237			end loop;
238			return result;
239		end;
240	
241		function sof(slv : T_SLV_32) return T_SIM_STREAM_WORD_32 is
242			variable result : T_SIM_STREAM_WORD_32;
243		begin
244			result := (Valid => '1', Data	=> slv,	SOF	=> '1',	EOF	=> '0', Ready => '-', EOFG => FALSE);
245			report "sof: " & to_string(result) severity NOTE;
246			return result;
247		end;
248	
249		function sof(slvv : T_SLVV_32) return T_SIM_STREAM_WORD_VECTOR_32 is
250			variable result			: T_SIM_STREAM_WORD_VECTOR_32(slvv'range);
251		begin
252			result(slvv'low)		:= sof(slvv(slvv'low));
253			for i in slvv'low + 1 to slvv'high loop
254				result(i)		:= dat(slvv(i));
255			end loop;
256			return result;
257		end;
258	
259		function eof(slv : T_SLV_8) return T_SIM_STREAM_WORD_8 is
260			variable result : T_SIM_STREAM_WORD_8;
261		begin
262			result := (Valid => '1', Data	=> slv,	SOF	=> '0',	EOF	=> '1', Ready => '-', EOFG => FALSE);
263			report "eof: " & to_string(result) severity NOTE;
264			return result;
265		end;
266	
267		function eof(slvv : T_SLVV_8) return T_SIM_STREAM_WORD_VECTOR_8 is
268			variable result			: T_SIM_STREAM_WORD_VECTOR_8(slvv'range);
269		begin
270			for i in slvv'low to slvv'high - 1 loop
271				result(i)		:= dat(slvv(i));
272			end loop;
273			result(slvv'high)		:= eof(slvv(slvv'high));
274			return result;
275		end;
276	
277		function eof(slv : T_SLV_32) return T_SIM_STREAM_WORD_32 is
278			variable result : T_SIM_STREAM_WORD_32;
279		begin
280			result := (Valid => '1', Data	=> slv,	SOF	=> '0',	EOF	=> '1', Ready => '-', EOFG => FALSE);
281			report "eof: " & to_string(result) severity NOTE;
282			return result;
283		end;
284	
285		function eof(slvv : T_SLVV_32) return T_SIM_STREAM_WORD_VECTOR_32 is
286			variable result			: T_SIM_STREAM_WORD_VECTOR_32(slvv'range);
287		begin
288			for i in slvv'low to slvv'high - 1 loop
289				result(i)		:= dat(slvv(i));
290			end loop;
291			result(slvv'high)		:= eof(slvv(slvv'high));
292			return result;
293		end;
294	
295		function eof(stmw : T_SIM_STREAM_WORD_8) return T_SIM_STREAM_WORD_8 is
296		begin
297			return T_SIM_STREAM_WORD_8'(
298				Valid		=> stmw.Valid,
299				Data		=> stmw.Data,
300				SOF			=> stmw.SOF,
301				EOF			=> '1',
302				Ready		=> '-',
303				EOFG		=> stmw.EOFG);
304		end function;
305	
306		function eof(stmw : T_SIM_STREAM_WORD_32) return T_SIM_STREAM_WORD_32 is
307		begin
308			return T_SIM_STREAM_WORD_32'(
309				Valid		=> stmw.Valid,
310				Data		=> stmw.Data,
311				SOF			=> stmw.SOF,
312				EOF			=> '1',
313				Ready		=> '-',
314				EOFG		=> stmw.EOFG);
315		end function;
316	
317		function eof(stmwv : T_SIM_STREAM_WORD_VECTOR_8) return T_SIM_STREAM_WORD_VECTOR_8 is
318			variable result			: T_SIM_STREAM_WORD_VECTOR_8(stmwv'range);
319		begin
320			for i in stmwv'low to stmwv'high - 1 loop
321				result(i)		:= stmwv(i);
322			end loop;
323			result(stmwv'high)		:= eof(stmwv(stmwv'high));
324	
325			return result;
326		end;
327	
328		function eofg(stmw : T_SIM_STREAM_WORD_8) return T_SIM_STREAM_WORD_8 is
329		begin
330			return T_SIM_STREAM_WORD_8'(
331				Valid		=> stmw.Valid,
332				Data		=> stmw.Data,
333				SOF			=> stmw.SOF,
334				EOF			=> stmw.EOF,
335				Ready		=> stmw.Ready,
336				EOFG		=> TRUE);
337		end function;
338	
339		function eofg(stmw : T_SIM_STREAM_WORD_32) return T_SIM_STREAM_WORD_32 is
340		begin
341			return T_SIM_STREAM_WORD_32'(
342				Valid		=> stmw.Valid,
343				Data		=> stmw.Data,
344				SOF			=> stmw.SOF,
345				EOF			=> stmw.EOF,
346				Ready		=> stmw.Ready,
347				EOFG		=> TRUE);
348		end function;
349	
350		function eofg(stmwv : T_SIM_STREAM_WORD_VECTOR_8) return T_SIM_STREAM_WORD_VECTOR_8 is
351			variable result			: T_SIM_STREAM_WORD_VECTOR_8(stmwv'range);
352		begin
353			for i in stmwv'low to stmwv'high - 1 loop
354				result(i)		:= stmwv(i);
355			end loop;
356			result(stmwv'high)		:= eofg(stmwv(stmwv'high));
357	
358			return result;
359		end;
360	
361		function to_flag1_string(stmw : T_SIM_STREAM_WORD_8) return string is
362			variable flag : std_logic_vector(2 downto 0)	:= to_sl(stmw.EOFG) & stmw.EOF & stmw.SOF;
363		begin
364			case flag is
365				when "000" =>		return "";
366				when "001" =>		return "SOF";
367				when "010" =>		return "EOF";
368				when "011" =>		return "SOF+EOF";
369				when "100" =>		return "*";
370				when "101" =>		return "SOF*";
371				when "110" =>		return "EOF*";
372				when "111" =>		return "SOF+EOF*";
373				when others =>	return "ERROR";
374			end case;
375		end function;
376	
377		function to_flag1_string(stmw : T_SIM_STREAM_WORD_32) return string is
378			variable flag : std_logic_vector(2 downto 0)	:= to_sl(stmw.EOFG) & stmw.EOF & stmw.SOF;
379		begin
380			case flag is
381				when "000" =>		return "";
382				when "001" =>		return "SOF";
383				when "010" =>		return "EOF";
384				when "011" =>		return "SOF+EOF";
385				when "100" =>		return "*";
386				when "101" =>		return "SOF*";
387				when "110" =>		return "EOF*";
388				when "111" =>		return "SOF+EOF*";
389				when others =>	return "ERROR";
390			end case;
391		end function;
392	
393		function to_flag2_string(stmw : T_SIM_STREAM_WORD_8) return string is
394			variable flag : std_logic_vector(1 downto 0)	:= stmw.Ready & stmw.Valid;
395		begin
396			case flag is
397				when "00" =>		return "  ";
398				when "01" =>		return " V";
399				when "10" =>		return "R ";
400				when "11" =>		return "RV";
401				when "-0" =>		return "- ";
402				when "-1" =>		return "-V";
403				when others =>	return "??";
404			end case;
405		end function;
406	
407		function to_flag2_string(stmw : T_SIM_STREAM_WORD_32) return string is
408			variable flag : std_logic_vector(1 downto 0)	:= stmw.Ready & stmw.Valid;
409		begin
410			case flag is
411				when "00" =>		return "  ";
412				when "01" =>		return " V";
413				when "10" =>		return "R ";
414				when "11" =>		return "RV";
415				when "-0" =>		return "- ";
416				when "-1" =>		return "-V";
417				when others =>	return "??";
418			end case;
419		end function;
420	
421		function to_string(stmw : T_SIM_STREAM_WORD_8) return string is
422		begin
423			return to_flag2_string(stmw) & " 0x" & to_string(stmw.Data, 'h') & " " & to_flag1_string(stmw);
424		end function;
425	
426		function to_string(stmw : T_SIM_STREAM_WORD_32) return string is
427		begin
428			return to_flag2_string(stmw) & " 0x" & to_string(stmw.Data, 'h') & " " & to_flag1_string(stmw);
429		end function;
430	
431		-- checksum functions
432		-- ================================================================
433	--	-- Private function to_01 copied from GlobalTypes
434	--	function to_01(slv : STD_LOGIC_VECTOR) return STD_LOGIC_VECTOR is
435	--	begin
436	--	  return  to_stdlogicvector(to_bitvector(slv));
437	--	end;
438	
439		function sim_CRC8(words : T_SIM_STREAM_WORD_VECTOR_8) return std_logic_vector is
440			constant CRC8_INIT					: T_SLV_8					:= x"FF";
441			constant CRC8_POLYNOMIAL		: T_SLV_8					:= x"31";			-- 0x131
442	
443			variable CRC8_Value					: T_SLV_8					:= CRC8_INIT;
444	
445	--		variable Pattern						: T_DATAFifO_PATTERN;
446			variable Word								: unsigned(T_SLV_8'range);
447		begin
448			report "Computing CRC8 for Words " & to_string(words'low) & " to " & to_string(words'high) severity NOTE;
449	
450			for i in words'range loop
451				if (words(i).Valid = '1') then
452					Word	:= to_01(unsigned(words(i).Data));
453	
454	--					assert (J > 9) report str_merge("  Word: 0x", hstr(Word), "    CRC16_Value: 0x", hstr(CRC16_Value)) severity NOTE;
455	
456					for j in Word'range loop
457							CRC8_Value := (CRC8_Value(CRC8_Value'high - 1 downto 0) & '0') xor (CRC8_POLYNOMIAL and (CRC8_POLYNOMIAL'range => (Word(j) xor CRC8_Value(CRC8_Value'high))));
458					end loop;
459				end if;
460	
461				exit when (words(i).EOFG = TRUE);
462			end loop;
463	
464			report "  CRC8: 0x" & to_string(CRC8_Value, 'h') severity NOTE;
465	
466			return CRC8_Value;
467		end;
468	
