30	
31	library IEEE;
32	use			IEEE.STD_LOGIC_1164.all;
33	use			IEEE.NUMERIC_STD.all;
34	
35	library PoC;
36	use			PoC.config.all;
37	use			PoC.utils.all;
38	use			PoC.vectors.all;
39	
40	
41	entity stream_Mux is
42		generic (
43			PORTS							: positive									:= 2;
44			DATA_BITS					: positive									:= 8;
45			META_BITS					: natural										:= 8;
46			META_REV_BITS			: natural										:= 2--;
47	--		WEIGHTS						: T_INTVEC									:= (1, 1)
48		);
49		port (
50			Clock							: in	std_logic;
51			Reset							: in	std_logic;
52			-- IN Ports
53			In_Valid					: in	std_logic_vector(PORTS - 1 downto 0);
54			In_Data						: in	T_SLM(PORTS - 1 downto 0, DATA_BITS - 1 downto 0);
55			In_Meta						: in	T_SLM(PORTS - 1 downto 0, META_BITS - 1 downto 0);
56			In_Meta_rev				: out	T_SLM(PORTS - 1 downto 0, META_REV_BITS - 1 downto 0);
57			In_SOF						: in	std_logic_vector(PORTS - 1 downto 0);
58			In_EOF						: in	std_logic_vector(PORTS - 1 downto 0);
59			In_Ack						: out	std_logic_vector(PORTS - 1 downto 0);
60			-- OUT Port
61			Out_Valid					: out	std_logic;
62			Out_Data					: out	std_logic_vector(DATA_BITS - 1 downto 0);
63			Out_Meta					: out	std_logic_vector(META_BITS - 1 downto 0);
64			Out_Meta_rev			: in	std_logic_vector(META_REV_BITS - 1 downto 0);
65			Out_SOF						: out	std_logic;
66			Out_EOF						: out	std_logic;
67			Out_Ack						: in	std_logic
68		);
69	end entity;
70	
71	
72	architecture rtl of stream_Mux is
73		attribute KEEP										: boolean;
74		attribute FSM_ENCODING						: string;
75	
76		subtype T_CHANNEL_INDEX is natural range 0 to PORTS - 1;
77	
78		type T_STATE is (ST_IDLE, ST_DATAFLOW);
79	
80		signal State											: T_STATE					:= ST_IDLE;
81		signal NextState									: T_STATE;
82	
83		signal FSM_Dataflow_en						: std_logic;
84	
85		signal RequestVector							: std_logic_vector(PORTS - 1 downto 0);
86		signal RequestWithSelf						: std_logic;
87		signal RequestWithoutSelf					: std_logic;
88	
89		signal RequestLeft								: unsigned(PORTS - 1 downto 0);
90		signal SelectLeft									: unsigned(PORTS - 1 downto 0);
91		signal SelectRight								: unsigned(PORTS - 1 downto 0);
92	
93		signal ChannelPointer_en					: std_logic;
94		signal ChannelPointer							: std_logic_vector(PORTS - 1 downto 0);
95		signal ChannelPointer_d						: std_logic_vector(PORTS - 1 downto 0)						:= to_slv(2 ** (PORTS - 1), PORTS);
96		signal ChannelPointer_nxt					: std_logic_vector(PORTS - 1 downto 0);
97		signal ChannelPointer_bin					: unsigned(log2ceilnz(PORTS) - 1 downto 0);
98	
99		signal idx												: T_CHANNEL_INDEX;
100	
101		signal Out_EOF_i									: std_logic;
102	
103	begin
104		RequestVector				<= In_Valid and In_SOF;
105		RequestWithSelf			<= slv_or(RequestVector);
106		RequestWithoutSelf	<= slv_or(RequestVector and not ChannelPointer_d);
107	
108		process(Clock)
109		begin
110			if rising_edge(Clock) then
111				if (Reset = '1') then
112					State				<= ST_IDLE;
113				else
114					State				<= NextState;
115				end if;
116			end if;
117		end process;
118	
119		process(State, RequestWithSelf, RequestWithoutSelf, Out_Ack, Out_EOF_i, ChannelPointer_d, ChannelPointer_nxt)
120		begin
121			NextState									<= State;
122	
123			FSM_Dataflow_en						<= '0';
124	
125			ChannelPointer_en					<= '0';
126			ChannelPointer						<= ChannelPointer_d;
127	
128			case State is
129				when ST_IDLE =>
130					if (RequestWithSelf = '1') then
131						ChannelPointer_en		<= '1';
132	
133						NextState						<= ST_DATAFLOW;
134					end if;
135	
136				when ST_DATAFLOW =>
137					FSM_Dataflow_en				<= '1';
138	
139					if ((Out_Ack and Out_EOF_i) = '1') then
140						if (RequestWithoutSelf = '0') then
141							NextState					<= ST_IDLE;
142						else
143							ChannelPointer_en	<= '1';
144						end if;
145					end if;
146			end case;
147		end process;
148	
149		process(Clock)
150		begin
151			if rising_edge(Clock) then
152				if (Reset = '1') then
153					ChannelPointer_d			<= to_slv(2 ** (PORTS - 1), PORTS);
154				elsif (ChannelPointer_en = '1') then
155					ChannelPointer_d		<= ChannelPointer_nxt;
156				end if;
157			end if;
158		end process;
159	
160		RequestLeft					<= (not ((unsigned(ChannelPointer_d) - 1) or unsigned(ChannelPointer_d))) and unsigned(RequestVector);
161		SelectLeft					<= (unsigned(not RequestLeft) + 1)		and RequestLeft;
162		SelectRight					<= (unsigned(not RequestVector) + 1)	and unsigned(RequestVector);
163		ChannelPointer_nxt	<= std_logic_vector(ite((RequestLeft = (RequestLeft'range => '0')), SelectRight, SelectLeft));
164	
165		ChannelPointer_bin	<= onehot2bin(ChannelPointer);
166		idx									<= to_integer(ChannelPointer_bin);
167	
168		Out_Data						<= get_row(In_Data, idx);
169		Out_Meta						<= get_row(In_Meta, idx);
170	
171		Out_SOF							<= In_SOF(to_integer(ChannelPointer_bin));
172		Out_EOF_i						<= In_EOF(to_integer(ChannelPointer_bin));
173		Out_Valid						<= In_Valid(to_integer(ChannelPointer_bin)) and FSM_Dataflow_en;
174		Out_EOF							<= Out_EOF_i;
175	
176		In_Ack							<= (In_Ack	'range => (Out_Ack	 and FSM_Dataflow_en)) and ChannelPointer;
177	
178		genMetaReverse_0 : if META_REV_BITS = 0 generate
179			In_Meta_rev		<= (others => (others => '0'));
180		end generate;
181		genMetaReverse_1 : if META_REV_BITS > 0 generate
182			signal Temp_Meta_rev : T_SLM(PORTS - 1 downto 0, META_REV_BITS - 1 downto 0)		:= (others => (others => 'Z'));
183		begin
184			genAssign : for i in 0 to PORTS - 1 generate
185				signal row	: std_logic_vector(META_REV_BITS - 1 downto 0);
186			begin
187				row		<= Out_Meta_rev and (row'range => ChannelPointer(i));
188				assign_row(Temp_Meta_rev, row, i);
189			end generate;
190			In_Meta_rev		<= Temp_Meta_rev;
191		end generate;
192	
193	end architecture;
