30	
31	library IEEE;
32	use			IEEE.STD_LOGIC_1164.all;
33	use			IEEE.NUMERIC_STD.all;
34	
35	library PoC;
36	use			PoC.config.all;
37	use			PoC.utils.all;
38	use			PoC.vectors.all;
39	
40	
41	entity stream_DeMux is
42		generic (
43			PORTS							: positive									:= 2;
44			DATA_BITS					: positive									:= 8;
45			META_BITS					: natural										:= 8;
46			META_REV_BITS			: natural										:= 2
47		);
48		port (
49			Clock							: in	std_logic;
50			Reset							: in	std_logic;
51			-- Control interface
52			DeMuxControl			: in	std_logic_vector(PORTS - 1 downto 0);
53			-- IN Port
54			In_Valid					: in	std_logic;
55			In_Data						: in	std_logic_vector(DATA_BITS - 1 downto 0);
56			In_Meta						: in	std_logic_vector(META_BITS - 1 downto 0);
57			In_Meta_rev				: out	std_logic_vector(META_REV_BITS - 1 downto 0);
58			In_SOF						: in	std_logic;
59			In_EOF						: in	std_logic;
60			In_Ack						: out	std_logic;
61			-- OUT Ports
62			Out_Valid					: out	std_logic_vector(PORTS - 1 downto 0);
63			Out_Data					: out	T_SLM(PORTS - 1 downto 0, DATA_BITS - 1 downto 0);
64			Out_Meta					: out	T_SLM(PORTS - 1 downto 0, META_BITS - 1 downto 0);
65			Out_Meta_rev			: in	T_SLM(PORTS - 1 downto 0, META_REV_BITS - 1 downto 0);
66			Out_SOF						: out	std_logic_vector(PORTS - 1 downto 0);
67			Out_EOF						: out	std_logic_vector(PORTS - 1 downto 0);
68			Out_Ack						: in	std_logic_vector(PORTS - 1 downto 0)
69		);
70	end entity;
71	
72	
73	architecture rtl of stream_DeMux is
74		attribute KEEP										: boolean;
75		attribute FSM_ENCODING						: string;
76	
77		subtype T_CHANNEL_INDEX is natural range 0 to PORTS - 1;
78	
79		type T_STATE		is (ST_IDLE, ST_DATAFLOW, ST_DISCARD_FRAME);
80	
81		signal State								: T_STATE					:= ST_IDLE;
82		signal NextState						: T_STATE;
83	
84		signal Is_SOF								: std_logic;
85		signal Is_EOF								: std_logic;
86	
87		signal In_Ack_i							: std_logic;
88		signal Out_Valid_i					: std_logic;
89		signal DiscardFrame					: std_logic;
90	
91		signal ChannelPointer_rst		: std_logic;
92		signal ChannelPointer_en		: std_logic;
93		signal ChannelPointer				: std_logic_vector(PORTS - 1 downto 0);
94		signal ChannelPointer_d			: std_logic_vector(PORTS - 1 downto 0)								:= (others => '0');
95	
96		signal ChannelPointer_bin		: unsigned(log2ceilnz(PORTS) - 1 downto 0);
97		signal idx									: T_CHANNEL_INDEX;
98	
99		signal Out_Data_i						: T_SLM(PORTS - 1 downto 0, DATA_BITS - 1 downto 0)		:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
100		signal Out_Meta_i						: T_SLM(PORTS - 1 downto 0, META_BITS - 1 downto 0)		:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
101	begin
102	
103		In_Ack_i			<= slv_or(Out_Ack	 and ChannelPointer);
104		DiscardFrame	<= slv_nor(DeMuxControl);
105	
106		Is_SOF			<= In_Valid and In_SOF;
107		Is_EOF			<= In_Valid and In_EOF;
108	
109		process(Clock)
110		begin
111			if rising_edge(Clock) then
112				if (Reset = '1') then
113					State				<= ST_IDLE;
114				else
115					State				<= NextState;
116				end if;
117			end if;
118		end process;
119	
120		process(State, In_Ack_i, In_Valid, Is_SOF, Is_EOF, DiscardFrame, DeMuxControl, ChannelPointer_d)
121		begin
122			NextState									<= State;
123	
124			ChannelPointer_rst				<= Is_EOF;
125			ChannelPointer_en					<= '0';
126			ChannelPointer						<= ChannelPointer_d;
127	
128			In_Ack										<= '0';
129			Out_Valid_i								<= '0';
130	
131			case State is
132				when ST_IDLE =>
133					ChannelPointer					<= DeMuxControl;
134	
135					if (Is_SOF = '1') then
136						if (DiscardFrame = '0') then
137							ChannelPointer_en		<= '1';
138							In_Ack							<= In_Ack_i;
139							Out_Valid_i					<= '1';
140	
141							NextState						<= ST_DATAFLOW;
142						else
143							In_Ack							<= '1';
144	
145							NextState						<= ST_DISCARD_FRAME;
146						end if;
147					end if;
148	
149				when ST_DATAFLOW =>
150					In_Ack									<= In_Ack_i;
151					Out_Valid_i							<= In_Valid;
152					ChannelPointer					<= ChannelPointer_d;
153	
154					if (Is_EOF = '1') then
155						NextState							<= ST_IDLE;
156					end if;
157	
158				when ST_DISCARD_FRAME =>
159					In_Ack									<= '1';
160	
161					if (Is_EOF = '1') then
162						NextState							<= ST_IDLE;
163					end if;
164			end case;
165		end process;
166	
167	
168		process(Clock)
169		begin
170			if rising_edge(Clock) then
171				if ((Reset or ChannelPointer_rst) = '1') then
172					ChannelPointer_d		<= (others => '0');
173				elsif (ChannelPointer_en = '1') then
174					ChannelPointer_d		<= DeMuxControl;
175				end if;
176			end if;
177		end process;
178	
179		ChannelPointer_bin	<= onehot2bin(ChannelPointer_d);
180		idx									<= to_integer(ChannelPointer_bin);
181	
182		In_Meta_rev					<= get_row(Out_Meta_rev, idx);
183	
184		genOutput : for i in 0 to PORTS - 1 generate
185			Out_Valid(i)			<= Out_Valid_i and ChannelPointer(i);
186			assign_row(Out_Data_i, In_Data, i);
187			assign_row(Out_Meta_i, In_Meta, i);
188			Out_SOF(i)				<= In_SOF;
189			Out_EOF(i)				<= In_EOF;
190		end generate;
191	
192		Out_Data		<= Out_Data_i;
193		Out_Meta		<= Out_Meta_i;
194	
195	end architecture;
