1	-- EMACS settings: -*-  tab-width: 2; indent-tabs-mode: t -*-
2	-- vim: tabstop=2:shiftwidth=2:noexpandtab
3	-- kate: tab-width 2; replace-tabs off; indent-width 2;
4	-- =============================================================================
5	-- Authors:				 	Patrick Lehmann
6	--
7	-- Entity:				 	A generic buffer module for the PoC.Stream protocol.
8	--
9	-- Description:
10	-- -------------------------------------
11	-- This module implements a generic buffer (FIFO) for the
12	-- :doc:`PoC.Stream </Interfaces/Stream>` protocol. It is generic in
13	-- ``DATA_BITS`` and in ``META_BITS`` as well as in FIFO depths for data and
14	-- meta information.
15	--
16	-- License:
17	-- =============================================================================
18	-- Copyright 2007-2015 Technische Universitaet Dresden - Germany
19	--										 Chair of VLSI-Design, Diagnostics and Architecture
20	--
21	-- Licensed under the Apache License, Version 2.0 (the "License");
22	-- you may not use this file except in compliance with the License.
23	-- You may obtain a copy of the License at
24	--
25	--		http://www.apache.org/licenses/LICENSE-2.0
26	--
27	-- Unless required by applicable law or agreed to in writing, software
28	-- distributed under the License is distributed on an "AS IS" BASIS,
29	-- WITHOUT WARRANTIES OR CONDITIONS of ANY KIND, either express or implied.
30	-- See the License for the specific language governing permissions and
31	-- limitations under the License.
32	-- =============================================================================
33	
34	library IEEE;
35	use			IEEE.STD_LOGIC_1164.all;
36	use			IEEE.NUMERIC_STD.all;
37	
38	library PoC;
39	use			PoC.config.all;
40	use			PoC.utils.all;
41	use			PoC.vectors.all;
42	
43	
44	entity stream_Buffer is
45		generic (
46			FRAMES						: positive																								:= 2;
47			DATA_BITS					: positive																								:= 8;
48			DATA_FIFO_DEPTH		: positive																								:= 8;
49			META_BITS					: T_POSVEC																								:= (0 => 8);
50			META_FIFO_DEPTH		: T_POSVEC																								:= (0 => 16)
51		);
52		port (
53			Clock							: in	std_logic;
54			Reset							: in	std_logic;
55			-- IN Port
56			In_Valid					: in	std_logic;
57			In_Data						: in	std_logic_vector(DATA_BITS - 1 downto 0);
58			In_SOF						: in	std_logic;
59			In_EOF						: in	std_logic;
60			In_Ack						: out	std_logic;
61			In_Meta_rst				: out	std_logic;
62			In_Meta_nxt				: out	std_logic_vector(META_BITS'length - 1 downto 0);
63			In_Meta_Data			: in	std_logic_vector(isum(META_BITS) - 1 downto 0);
64			-- OUT Port
65			Out_Valid					: out	std_logic;
66			Out_Data					: out	std_logic_vector(DATA_BITS - 1 downto 0);
67			Out_SOF						: out	std_logic;
68			Out_EOF						: out	std_logic;
69			Out_Ack						: in	std_logic;
70			Out_Meta_rst			: in	std_logic;
71			Out_Meta_nxt			: in	std_logic_vector(META_BITS'length - 1 downto 0);
72			Out_Meta_Data			: out	std_logic_vector(isum(META_BITS) - 1 downto 0)
73		);
74	end entity;
75	
76	
77	architecture rtl of stream_Buffer is
78		attribute FSM_ENCODING						: string;
79	
80		constant META_STREAMS							: positive																						:= META_BITS'length;
81	
82		type T_WRITER_STATE is (ST_IDLE, ST_FRAME);
83		type T_READER_STATE is (ST_IDLE, ST_FRAME);
84	
85		signal Writer_State								: T_WRITER_STATE																			:= ST_IDLE;
86		signal Writer_NextState						: T_WRITER_STATE;
87		signal Reader_State								: T_READER_STATE																			:= ST_IDLE;
88		signal Reader_NextState						: T_READER_STATE;
89	
90		constant EOF_BIT									: natural																							:= DATA_BITS;
91	
92		signal DataFIFO_put								: std_logic;
93		signal DataFIFO_DataIn						: std_logic_vector(DATA_BITS downto 0);
94		signal DataFIFO_Full							: std_logic;
95	
96		signal DataFIFO_got								: std_logic;
97		signal DataFIFO_DataOut						: std_logic_vector(DataFIFO_DataIn'range);
98		signal DataFIFO_Valid							: std_logic;
99	
100		signal FrameCommit								: std_logic;
101		signal Meta_rst										: std_logic_vector(META_BITS'length - 1 downto 0);
102	
103	begin
104		assert (META_BITS'length = META_FIFO_DEPTH'length) report "META_BITS'length /= META_FIFO_DEPTH'length" severity FAILURE;
105	
106		process(Clock)
107		begin
108			if rising_edge(Clock) then
109				if (Reset = '1') then
110					Writer_State					<= ST_IDLE;
111					Reader_State					<= ST_IDLE;
112				else
113					Writer_State					<= Writer_NextState;
114					Reader_State					<= Reader_NextState;
115				end if;
116			end if;
117		end process;
118	
119		process(Writer_State,
120						In_Valid, In_Data, In_SOF, In_EOF,
121						DataFIFO_Full)
122		begin
123			Writer_NextState									<= Writer_State;
124	
125			In_Ack														<= '0';
126	
127			DataFIFO_put											<= '0';
128			DataFIFO_DataIn(In_Data'range)		<= In_Data;
129			DataFIFO_DataIn(EOF_BIT)					<= In_EOF;
130	
131			case Writer_State is
132				when ST_IDLE =>
133					In_Ack												<= not DataFIFO_Full;
134					DataFIFO_put									<= In_Valid;
135	
136					if ((In_Valid and In_SOF and not In_EOF) = '1') then
137	
138						Writer_NextState						<= ST_FRAME;
139					end if;
140	
141				when ST_FRAME =>
142					In_Ack												<= not DataFIFO_Full;
143					DataFIFO_put									<= In_Valid;
144	
145					if ((In_Valid and In_EOF and not DataFIFO_Full) = '1') then
146	
147						Writer_NextState						<= ST_IDLE;
148					end if;
149			end case;
150		end process;
151	
152	
153		process(Reader_State,
154						Out_Ack,
155						DataFIFO_Valid, DataFIFO_DataOut)
156		begin
157			Reader_NextState								<= Reader_State;
158	
159			Out_Valid												<= '0';
160			Out_Data												<= DataFIFO_DataOut(Out_Data'range);
161			Out_SOF													<= '0';
162			Out_EOF													<= DataFIFO_DataOut(EOF_BIT);
163	
164			DataFIFO_got										<= '0';
165	
166			case Reader_State is
167				when ST_IDLE =>
168					Out_Valid										<= DataFIFO_Valid;
169					Out_SOF											<= '1';
170					DataFIFO_got								<= Out_Ack;
171	
172					if ((DataFIFO_Valid and not DataFIFO_DataOut(EOF_BIT) and Out_Ack) = '1') then
173						Reader_NextState					<= ST_FRAME;
174					end if;
175	
176				when ST_FRAME =>
177					Out_Valid										<= DataFIFO_Valid;
178					DataFIFO_got								<= Out_Ack;
179	
180					if ((DataFIFO_Valid and DataFIFO_DataOut(EOF_BIT) and Out_Ack) = '1') then
181						Reader_NextState					<= ST_IDLE;
182					end if;
183	
184			end case;
185		end process;
186	
187		DataFIFO : entity PoC.fifo_cc_got
188			generic map (
189				D_BITS							=> DATA_BITS + 1,								-- Data Width
190				MIN_DEPTH						=> (DATA_FIFO_DEPTH * FRAMES),	-- Minimum FIFO Depth
191				DATA_REG						=> ((DATA_FIFO_DEPTH * FRAMES) <= 128),											-- Store Data Content in Registers
192				STATE_REG						=> TRUE,												-- Registered Full/Empty Indicators
193				OUTPUT_REG					=> FALSE,												-- Registered FIFO Output
194				ESTATE_WR_BITS			=> 0,														-- Empty State Bits
195				FSTATE_RD_BITS			=> 0														-- Full State Bits
196			)
197			port map (
198				-- Global Reset and Clock
199				clk									=> Clock,
200				rst									=> Reset,
201	
202				-- Writing Interface
203				put									=> DataFIFO_put,
204				din									=> DataFIFO_DataIn,
205				full								=> DataFIFO_Full,
206				estate_wr						=> open,
207	
208				-- Reading Interface
209				got									=> DataFIFO_got,
210				dout								=> DataFIFO_DataOut,
211				valid								=> DataFIFO_Valid,
212				fstate_rd						=> open
213			);
214	
215		FrameCommit		<= DataFIFO_Valid and DataFIFO_DataOut(EOF_BIT) and Out_Ack;
216		In_Meta_rst		<= slv_and(Meta_rst);
217	
218		genMeta : for i in 0 to META_BITS'length - 1 generate
219	
220		begin
221			genReg : if META_FIFO_DEPTH(i) = 1 generate
222				signal MetaReg_DataIn				: std_logic_vector(META_BITS(i) - 1 downto 0);
223				signal MetaReg_d						: std_logic_vector(META_BITS(i) - 1 downto 0)		:= (others => '0');
224				signal MetaReg_DataOut			: std_logic_vector(META_BITS(i) - 1 downto 0);
225			begin
226				MetaReg_DataIn		<= In_Meta_Data(high(META_BITS, i) downto low(META_BITS, i));
227	
228				process(Clock)
229				begin
230					if rising_edge(Clock) then
231						if (Reset = '1') then
232							MetaReg_d			<= (others => '0');
233						elsif ((In_Valid and In_SOF) = '1') then
234							MetaReg_d			<= MetaReg_DataIn;
235						end if;
236					end if;
237				end process;
238	
239				MetaReg_DataOut		<= MetaReg_d;
240				Out_Meta_Data(high(META_BITS, i) downto low(META_BITS, i))	<= MetaReg_DataOut;
241			end generate;	-- META_FIFO_DEPTH(i) = 1
242			genFIFO : if META_FIFO_DEPTH(i) > 1 generate
243				signal MetaFIFO_put								: std_logic;
244				signal MetaFIFO_DataIn						: std_logic_vector(META_BITS(i) - 1 downto 0);
245				signal MetaFIFO_Full							: std_logic;
246	
247				signal MetaFIFO_Commit						: std_logic;
248				signal MetaFIFO_Rollback					: std_logic;
249	
250				signal MetaFIFO_got								: std_logic;
251				signal MetaFIFO_DataOut						: std_logic_vector(MetaFIFO_DataIn'range);
252				signal MetaFIFO_Valid							: std_logic;
253	
254				signal Writer_CounterControl			: std_logic																																:= '0';
255				signal Writer_Counter_en					: std_logic;
256				signal Writer_Counter_us					: unsigned(log2ceilnz(META_FIFO_DEPTH(i)) - 1 downto 0)										:= (others => '0');
257			begin
258				process(Clock)
259				begin
260					if rising_edge(Clock) then
261						if (Reset = '1') then
262							Writer_CounterControl			<= '0';
263						elsif ((In_Valid and In_SOF) = '1') then
264							Writer_CounterControl			<= '1';
265						elsif Writer_Counter_us = (META_FIFO_DEPTH(i) - 1) then
266							Writer_CounterControl			<= '0';
267						end if;
268					end if;
269				end process;
270	
271				Writer_Counter_en		<= (In_Valid and In_SOF) or Writer_CounterControl;
272	
273				process(Clock)
274				begin
275					if rising_edge(Clock) then
276						if (Writer_Counter_en = '0') then
277							Writer_Counter_us					<= (others => '0');
278						else
279							Writer_Counter_us					<= Writer_Counter_us + 1;
280						end if;
281					end if;
282				end process;
283	
284				Meta_rst(i)					<= not Writer_Counter_en;
285				In_Meta_nxt(i)			<= Writer_Counter_en;
286	
287				MetaFIFO_put				<= Writer_Counter_en;
288				MetaFIFO_DataIn			<= In_Meta_Data(high(META_BITS, i) downto low(META_BITS, i));
289	
290				MetaFIFO : entity PoC.fifo_cc_got_tempgot
291					generic map (
292						D_BITS							=> META_BITS(i),										-- Data Width
293						MIN_DEPTH						=> (META_FIFO_DEPTH(i) * FRAMES),		-- Minimum FIFO Depth
294						DATA_REG						=> TRUE,														-- Store Data Content in Registers
295						STATE_REG						=> FALSE,														-- Registered Full/Empty Indicators
296						OUTPUT_REG					=> FALSE,														-- Registered FIFO Output
297						ESTATE_WR_BITS			=> 0,																-- Empty State Bits
298						FSTATE_RD_BITS			=> 0																-- Full State Bits
299					)
300					port map (
301						-- Global Reset and Clock
302						clk									=> Clock,
303						rst									=> Reset,
304	
305						-- Writing Interface
306						put									=> MetaFIFO_put,
307						din									=> MetaFIFO_DataIn,
308						full								=> MetaFIFO_Full,
309						estate_wr						=> open,
310	
311						-- Reading Interface
312						got									=> MetaFIFO_got,
313						dout								=> MetaFIFO_DataOut,
314						valid								=> MetaFIFO_Valid,
315						fstate_rd						=> open,
316	
317						commit							=> MetaFIFO_Commit,
318						rollback						=> MetaFIFO_Rollback
319					);
320	
321				MetaFIFO_got				<= Out_Meta_nxt(i);
322				MetaFIFO_Commit			<= FrameCommit;
323				MetaFIFO_Rollback		<= Out_Meta_rst;
324	
325				Out_Meta_Data(high(META_BITS, i) downto low(META_BITS, i))	<= MetaFIFO_DataOut;
326			end generate;	-- (META_FIFO_DEPTH(i) > 1)
327		end generate;
328	
329	end architecture;
330

