30	
31	library IEEE;
32	use			IEEE.STD_LOGIC_1164.all;
33	use			IEEE.NUMERIC_STD.all;
34	
35	library PoC;
36	use			PoC.config.all;
37	use			PoC.utils.all;
38	use			PoC.vectors.all;
39	
40	
41	entity stream_Mirror is
42		generic (
43			PORTS							: positive									:= 2;
44			DATA_BITS					: positive									:= 8;
45			META_BITS					: T_POSVEC									:= (0 => 8);
46			META_LENGTH				: T_POSVEC									:= (0 => 16)
47		);
48		port (
49			Clock							: in	std_logic;
50			Reset							: in	std_logic;
51			-- IN Port
52			In_Valid					: in	std_logic;
53			In_Data						: in	std_logic_vector(DATA_BITS - 1 downto 0);
54			In_SOF						: in	std_logic;
55			In_EOF						: in	std_logic;
56			In_Ack						: out	std_logic;
57			In_Meta_rst				: out	std_logic;
58			In_Meta_nxt				: out	std_logic_vector(META_BITS'length - 1 downto 0);
59			In_Meta_Data			: in	std_logic_vector(isum(META_BITS) - 1 downto 0);
60			-- OUT Port
61			Out_Valid					: out	std_logic_vector(PORTS - 1 downto 0);
62			Out_Data					: out	T_SLM(PORTS - 1 downto 0, DATA_BITS - 1 downto 0);
63			Out_SOF						: out	std_logic_vector(PORTS - 1 downto 0);
64			Out_EOF						: out	std_logic_vector(PORTS - 1 downto 0);
65			Out_Ack						: in	std_logic_vector(PORTS - 1 downto 0);
66			Out_Meta_rst			: in	std_logic_vector(PORTS - 1 downto 0);
67			Out_Meta_nxt			: in	T_SLM(PORTS - 1 downto 0, META_BITS'length - 1 downto 0);
68			Out_Meta_Data			: out	T_SLM(PORTS - 1 downto 0, isum(META_BITS) - 1 downto 0)
69		);
70	end entity;
71	
72	
73	architecture rtl of stream_Mirror is
74		attribute KEEP							: boolean;
75		attribute FSM_ENCODING			: string;
76	
77		signal FIFOGlue_put					: std_logic;
78		signal FIFOGlue_DataIn			: std_logic_vector(DATA_BITS + 1 downto 0);
79		signal FIFOGlue_Full				: std_logic;
80		signal FIFOGlue_Valid				: std_logic;
81		signal FIFOGlue_DataOut			: std_logic_vector(DATA_BITS + 1 downto 0);
82		signal FIFOGlue_got					: std_logic;
83	
84		signal Ack_i								: std_logic;
85		signal Mask_r								: std_logic_vector(PORTS - 1 downto 0)												:= (others => '1');
86	
87		signal MetaOut_rst					: std_logic_vector(PORTS - 1 downto 0);
88	
89		signal Out_Data_i						: T_SLM(PORTS - 1 downto 0, DATA_BITS - 1 downto 0)						:= (others => (others => 'Z'));
90		signal Out_Meta_Data_i			: T_SLM(PORTS - 1 downto 0, isum(META_BITS) - 1 downto 0)			:= (others => (others => 'Z'));
91	begin
92	
93		-- Data path
94		-- ==========================================================================================================================================================
95		FIFOGlue_put															<= In_Valid;
96		FIFOGlue_DataIn(DATA_BITS - 1 downto 0)		<= In_Data;
97		FIFOGlue_DataIn(DATA_BITS + 0)						<= In_SOF;
98		FIFOGlue_DataIn(DATA_BITS + 1)						<= In_EOF;
99	
100		In_Ack																		<= not FIFOGlue_Full;
101	
102		FIFOGlue : entity PoC.fifo_glue
103			generic map (
104				D_BITS		=> DATA_BITS + 2					-- Data Width
105			)
106			port map (
107				-- Control
108				clk				=> Clock,									-- Clock
109				rst				=> Reset,									-- Synchronous Reset
110	
111				-- Input
112				put				=> FIFOGlue_put,					-- Put Value
113				di				=> FIFOGlue_DataIn,				-- Data Input
114				ful				=> FIFOGlue_Full,					-- Full
115	
116				-- Output
117				vld				=> FIFOGlue_Valid,				-- Data Available
118				do				=> FIFOGlue_DataOut,			-- Data Output
119				got				=> FIFOGlue_got						-- Data Consumed
120	  );
121	
122		genPorts : for i in 0 to PORTS - 1 generate
123			assign_row(Out_Data_i, FIFOGlue_DataOut(DATA_BITS - 1 downto 0), i);
124		end generate;
125	
126		Ack_i					<= slv_and(Out_Ack) or slv_and(not Mask_r or Out_Ack);
127		FIFOGlue_got	<= Ack_i;
128	
129		Out_Valid			<= (PORTS - 1 downto 0 => FIFOGlue_Valid) and Mask_r;
130		Out_Data			<= Out_Data_i;
131		Out_SOF				<= (PORTS - 1 downto 0 => FIFOGlue_DataOut(DATA_BITS + 0));
132		Out_EOF				<= (PORTS - 1 downto 0 => FIFOGlue_DataOut(DATA_BITS + 1));
133	
134		process(Clock)
135		begin
136			if rising_edge(Clock) then
137				if ((Reset or Ack_i	) = '1') then
138					Mask_r		<= (others => '1');
139				else
140					Mask_r		<= Mask_r and not Out_Ack;
141				end if;
142			end if;
143		end process;
144	
145		-- Metadata path
146		-- ==========================================================================================================================================================
147		In_Meta_rst		<= slv_and(MetaOut_rst);
148	
149		genMeta : for i in 0 to META_BITS'length - 1 generate
150			subtype T_METAMEMORY						is std_logic_vector(META_BITS(i) - 1 downto 0);
151			type T_METAMEMORY_VECTOR				is array(natural range <>) of T_METAMEMORY;
152	
153		begin
154			genReg : if META_LENGTH(i) = 1 generate
155				signal MetaMemory_en					: std_logic;
156				signal MetaMemory							: T_METAMEMORY;
157			begin
158				MetaMemory_en		<= In_Valid and In_SOF;
159	
160				process(Clock)
161				begin
162					if rising_edge(Clock) then
163						if (MetaMemory_en = '1') then
164							MetaMemory		<= In_Meta_Data(high(META_BITS, i) downto low(META_BITS, i));
165						end if;
166					end if;
167				end process;
168	
169				genReader : for j in 0 to PORTS - 1 generate
170					assign_row(Out_Meta_Data_i, MetaMemory, J, high(META_BITS, i), low(META_BITS, i));
171				end generate;
172			end generate;
173			genMem : if META_LENGTH(i) > 1 generate
174				signal MetaMemory_en					: std_logic;
175				signal MetaMemory							: T_METAMEMORY_VECTOR(META_LENGTH(i) - 1 downto 0);
176	
177				signal Writer_CounterControl	: std_logic																						:= '0';
178	
179				signal Writer_en							: std_logic;
180				signal Writer_rst							: std_logic;
181				signal Writer_us							: unsigned(log2ceilnz(META_LENGTH(i)) - 1 downto 0)		:= (others => '0');
182			begin
183				-- MetaMemory Write Pointer Control
184				process(Clock)
185				begin
186					if rising_edge(Clock) then
187						if (Reset = '1') then
188							Writer_CounterControl			<= '0';
189						else
190							if ((In_Valid and In_SOF) = '1') then
191								Writer_CounterControl		<= '1';
192							elsif Writer_us = (META_LENGTH(i) - 1) then
193								Writer_CounterControl		<= '0';
194							end if;
195						end if;
196					end if;
197				end process;
198	
199				Writer_en				<= (In_Valid and In_SOF) or Writer_CounterControl;
200	
201				In_Meta_nxt(i)	<= Writer_en;
202				MetaMemory_en		<= Writer_en;
203				MetaOut_rst(i)	<= not Writer_en;
204	
205				-- MetaMemory - Write Pointer
206				process(Clock)
207				begin
208					if rising_edge(Clock) then
209						if (Writer_en = '0') then
210							Writer_us			<= (others => '0');
211						else
212							Writer_us			<= Writer_us + 1;
213						end if;
214					end if;
215				end process;
216	
217				-- MetaMemory
218				process(Clock)
219				begin
220					if rising_edge(Clock) then
221						if (MetaMemory_en = '1') then
222							MetaMemory(to_integer(Writer_us))		<= In_Meta_Data(high(META_BITS, i) downto low(META_BITS, i));
223						end if;
224					end if;
225				end process;
226	
227				genReader : for j in 0 to PORTS - 1 generate
228					signal Row							: T_METAMEMORY;
229	
230					signal Reader_en				: std_logic;
231					signal Reader_rst				: std_logic;
232					signal Reader_us				: unsigned(log2ceilnz(META_LENGTH(i)) - 1 downto 0)		:= (others => '0');
233				begin
234					Reader_rst		<= Out_Meta_rst(j) or (In_Valid and In_SOF);
235					Reader_en			<= Out_Meta_nxt(j, i);
236	
237					process(Clock)
238					begin
239						if rising_edge(Clock) then
240							if (Reader_rst = '1') then
241								Reader_us			<= (others => '0');
242							elsif (Reader_en = '1') then
243								Reader_us			<= Reader_us + 1;
244							end if;
245						end if;
246					end process;
247	
248					Row <= MetaMemory(to_integer(Reader_us));
249					assign_row(Out_Meta_Data_i, Row, j, high(META_BITS, i), low(META_BITS, i));
250				end generate;		-- for each port
251			end generate;		-- if length > 1
252		end generate;		-- for each metadata stream
253	
254		Out_Meta_Data		<= Out_Meta_Data_i;
255	
256	end architecture;
